SELECT COUNT(member_master.um_code) AS count FROM TBL_B2B_MEMBER_MASTER member_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON member_master.UM_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND member_master.UM_UIS_CODE = #{searchUisCode}
AND member_master.UM_USEYN = #{searchUseYn}
AND member_master.UM_GROUP_CODE = #{searchMemberGroup}
AND ( member_master.UM_USERID LIKE CONCAT('%', #{searchName2}, '%') OR member_master.UM_NAME LIKE CONCAT('%', #{searchName2}, '%') )
AND member_master.UM_REGDATE >= #{searchStartDate}
AND member_master.UM_REGDATE <= #{searchEndDate}

SELECT member_master.UM_CODE AS um_code , institution_master.UIS_NAME AS uis_name , member_master.UM_USERID AS um_userid , member_master.UM_NAME AS um_name , member_master.UM_USEYN AS um_useyn , (SELECT COUNT(UMD_CODE) FROM TBL_MEMBER_DEVICE WHERE UMD_UM_CODE = member_master.um_code ) AS device_count , DATE_FORMAT(member_master.UM_REGDATE, '%Y-%m-%d %H:%i:%s') AS um_regdate FROM TBL_B2B_MEMBER_MASTER member_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON member_master.UM_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND member_master.UM_UIS_CODE = #{searchUisCode}
AND member_master.UM_USEYN = #{searchUseYn}
AND member_master.UM_GROUP_CODE = #{searchMemberGroup}
AND ( member_master.UM_USERID LIKE CONCAT('%', #{searchName2}, '%') OR member_master.UM_NAME LIKE CONCAT('%', #{searchName2}, '%') )
AND member_master.UM_REGDATE >= #{searchStartDate}
AND member_master.UM_REGDATE <= #{searchEndDate}
ORDER BY member_master.${sortField1}
ORDER BY member_master.UM_REGDATE DESC
LIMIT #{pagenum}, #{pageSize}

SELECT COUNT(member_master.um_code) AS count FROM TBL_B2B_MEMBER_MASTER member_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON member_master.UM_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1
AND member_master.UM_UIS_CODE = #{searchUisCode}
AND UM_USERID != #{searchExceptUserId}
AND UM_USEYN = #{searchUseYn}

