mapper.insert:
INSERT INTO TBL_B2B_MEMBER_MASTER
(
	UM_CODE,					UM_USERID,				UM_PWD,
	UM_UIS_CODE,				UM_REG_TYPE,			UM_TEL, 			
	UM_EMAIL,					UM_NAME,
	UM_REG_USERID,				UM_USEYN

	, UM_GROUP_CODE


	, UM_RANK


	, UM_GROUP


	, UM_FREE_ACCOUNT


	, UM_USER_TYPE


	, UM_SCHOOL_GRADE


	, UM_SCHOOL_CLASS


)
VALUES
(
	CONCAT('UM',LPAD(#{um_code},11,'0')),		#{um_userid},		PASSWORD(#{um_pwd}),
	#{um_uis_code}, 							'C',				'--', 				
	'@',										#{um_name}, 
	'admin',		 							'Y'

	, #{um_group_code}


	, #{um_rank}


	, #{um_group}


	, #{um_free_account}


	, #{um_user_type}


	, #{um_school_grade}


	, #{um_school_class}

)

mapper.update:
UPDATE TBL_B2B_MEMBER_MASTER
SET
	UM_PWD					= PASSWORD(#{um_pwd})

	, UM_NAME			= #{UM_NAME}


	, UM_GROUP_CODE			= #{um_group_code}


	, UM_GROUP = #{um_group}


	, UM_USER_TYPE = #{um_user_type}


	, UM_SCHOOL_GRADE = #{um_school_grade}


	, UM_SCHOOL_CLASS = #{um_school_class} 


	, UM_USEYN = #{um_useyn} 

WHERE
	UM_UIS_CODE				= #{um_uis_code}
AND
	UM_USERID = #{um_userid}
